        <meta charset="utf-8">
        <meta http-equiv="X-UA-Compatible" content="IE=edge">
        <meta name="viewport" content="width=device-width,initial-scale=1.0">
        <title>Plus</title>
        <link rel="preconnect" href="https://fonts.gstatic.com">
        <link href="https://fonts.googleapis.com/css2?family=Montserrat:wght@500&amp;display=swap" rel="stylesheet">
        <link href="https://fonts.googleapis.com/css2?family=Montserrat:wght@500;700&amp;display=swap" rel="stylesheet">
        <style>
          .header-wrapper {
            box-shadow: 0 3px 7px #0000000D;
            background-color: white;
          }
          .header {
            height: 94px;
            width: 100%;
            display: flex;
            justify-content: space-between;
            max-width: 1232px;
            margin: 0 auto;
          }
          .logo {
            height: 40px;
            width: auto;
            margin: 24px 12px;
          }
          .phone-link {
            display: flex;
            justify-content: center;
            align-items: center;
            text-decoration: none;
            min-width: 400px;
            color: white;
            background-color: #35B44A;
            font: 16px/19px $GPPTextRegular;
            padding-right: 20px;
          }
          .phone-icon {
            height: 40px;
            margin: 20px;
          }
          .main {
            padding: 66px;
          }
          .content-wrapper {
            margin: 0 auto;
            background-color: white;
            max-width: 816px;
            display: flex;
            flex-direction: column;
            padding: 40px 0;
            text-align: center;
          }
          .image {
            width: 100%;
            max-width: 604px;
            margin: 0 auto;
          }
          .text {
            padding-top: 40px;
            text-align: center;
          }

          @media (max-width: 735px) {
            .header {
              height: 64px;
            }
            .logo {
              height: 34px;
              margin: 15px 20px;
            }
          }
        </style>
      <style>@media print {#ghostery-tracker-tally {display:none !important}}</style>

